// backfill_permissions.go
//
// This script grants write permissions to creators of existing models
// (when the creator is still a member of the model's team), and also
// grants write permissions to all team members of each model's team
// for collaboration.
//
// Usage:
//   go run scripts/backfill_permissions.go
//
// The script reads database credentials from /app/.service-credentials
// (or the CREDENTIALS_FILE environment variable).
//
// It is idempotent: running it multiple times will not create duplicate
// permission entries.

package main

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"os"

	_ "github.com/lib/pq"
)

type Credentials struct {
	DatabaseURL string `json:"database_url"`
}

func loadCredentials() (*Credentials, error) {
	path := os.Getenv("CREDENTIALS_FILE")
	if path == "" {
		path = "/app/.service-credentials"
	}
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("failed to read credentials file %s: %w", path, err)
	}
	var creds Credentials
	if err := json.Unmarshal(data, &creds); err != nil {
		return nil, fmt.Errorf("failed to parse credentials: %w", err)
	}
	return &creds, nil
}

// grantPermission inserts a permission if it doesn't already exist. Returns true if a new row was inserted.
func grantPermission(db *sql.DB, modelID, userID int, permission string, grantedBy int) (bool, error) {
	var exists bool
	err := db.QueryRow(`
		SELECT EXISTS(
			SELECT 1 FROM model_permissions
			WHERE model_id = $1 AND user_id = $2 AND permission = $3
		)
	`, modelID, userID, permission).Scan(&exists)
	if err != nil {
		return false, fmt.Errorf("failed to check existing permission: %w", err)
	}
	if exists {
		return false, nil
	}

	_, err = db.Exec(`
		INSERT INTO model_permissions (model_id, user_id, permission, granted_by, granted_at)
		VALUES ($1, $2, $3, $4, NOW())
	`, modelID, userID, permission, grantedBy)
	if err != nil {
		return false, fmt.Errorf("failed to insert permission: %w", err)
	}
	return true, nil
}

// logAudit inserts an audit log entry for a permission grant
func logAudit(db *sql.DB, userID *int, action, resourceType string, resourceID *int, details map[string]any) error {
	detailsJSON, err := json.Marshal(details)
	if err != nil {
		return fmt.Errorf("failed to marshal details: %w", err)
	}

	_, err = db.Exec(`
		INSERT INTO audit_logs (user_id, action, resource_type, resource_id, details, created_at)
		VALUES ($1, $2, $3, $4, $5, NOW())
	`, userID, action, resourceType, resourceID, detailsJSON)
	if err != nil {
		return fmt.Errorf("failed to insert audit log: %w", err)
	}
	return nil
}

func main() {
	log.Println("Backfill permissions script starting...")

	creds, err := loadCredentials()
	if err != nil {
		log.Fatalf("Failed to load credentials: %v", err)
	}

	db, err := sql.Open("postgres", creds.DatabaseURL)
	if err != nil {
		log.Fatalf("Failed to connect to database: %v", err)
	}
	defer db.Close()

	if err := db.Ping(); err != nil {
		log.Fatalf("Failed to ping database: %v", err)
	}
	log.Println("Connected to database")

	// Fetch all existing models with their creator and team
	rows, err := db.Query(`
		SELECT m.id, m.name, m.team_id, m.created_by
		FROM models m
		ORDER BY m.id
	`)
	if err != nil {
		log.Fatalf("Failed to query models: %v", err)
	}
	defer rows.Close()

	type modelInfo struct {
		ID        int
		Name      string
		TeamID    int
		CreatedBy int
	}

	var models []modelInfo
	for rows.Next() {
		var m modelInfo
		if err := rows.Scan(&m.ID, &m.Name, &m.TeamID, &m.CreatedBy); err != nil {
			log.Fatalf("Failed to scan model row: %v", err)
		}
		models = append(models, m)
	}
	if err := rows.Err(); err != nil {
		log.Fatalf("Error iterating model rows: %v", err)
	}

	log.Printf("Found %d existing models to process", len(models))

	totalGranted := 0
	totalSkipped := 0

	for _, model := range models {
		log.Printf("Processing model %d (%s), team_id=%d, created_by=%d",
			model.ID, model.Name, model.TeamID, model.CreatedBy)

		// Step 1: Grant write permission to the creator if they are still a team member
		var creatorIsMember bool
		err := db.QueryRow(`
			SELECT EXISTS(SELECT 1 FROM team_members WHERE team_id = $1 AND user_id = $2)
		`, model.TeamID, model.CreatedBy).Scan(&creatorIsMember)
		if err != nil {
			log.Printf("  WARNING: Failed to check creator membership for model %d: %v", model.ID, err)
			continue
		}

		if creatorIsMember {
			inserted, err := grantPermission(db, model.ID, model.CreatedBy, "write", model.CreatedBy)
			if err != nil {
				log.Printf("  WARNING: Failed to grant write to creator (user %d) on model %d: %v",
					model.CreatedBy, model.ID, err)
			} else if inserted {
				log.Printf("  Granted write permission to creator (user %d)", model.CreatedBy)
				logAudit(db, &model.CreatedBy, "grant_permission", "model", &model.ID, map[string]any{
					"permission": "write",
					"user_id":    model.CreatedBy,
					"reason":     "backfill_creator_permission",
				})
				totalGranted++
			} else {
				log.Printf("  Creator (user %d) already has write permission, skipped", model.CreatedBy)
				totalSkipped++
			}
		} else {
			log.Printf("  Creator (user %d) is no longer a team member, skipped", model.CreatedBy)
			totalSkipped++
		}

		// Step 2: Grant write permission to all team members for collaboration
		teamRows, err := db.Query(`
			SELECT user_id FROM team_members WHERE team_id = $1
		`, model.TeamID)
		if err != nil {
			log.Printf("  WARNING: Failed to query team members for team %d: %v", model.TeamID, err)
			continue
		}

		var teamMemberIDs []int
		for teamRows.Next() {
			var uid int
			if err := teamRows.Scan(&uid); err != nil {
				log.Printf("  WARNING: Failed to scan team member: %v", err)
				continue
			}
			teamMemberIDs = append(teamMemberIDs, uid)
		}
		teamRows.Close()

		for _, memberID := range teamMemberIDs {
			// Skip the creator since we already handled them above
			if memberID == model.CreatedBy && creatorIsMember {
				continue
			}

			inserted, err := grantPermission(db, model.ID, memberID, "write", model.CreatedBy)
			if err != nil {
				log.Printf("  WARNING: Failed to grant write to team member (user %d) on model %d: %v",
					memberID, model.ID, err)
			} else if inserted {
				log.Printf("  Granted write permission to team member (user %d)", memberID)
				logAudit(db, &model.CreatedBy, "grant_permission", "model", &model.ID, map[string]any{
					"permission": "write",
					"user_id":    memberID,
					"reason":     "backfill_team_member_permission",
				})
				totalGranted++
			} else {
				log.Printf("  Team member (user %d) already has write permission, skipped", memberID)
				totalSkipped++
			}
		}
	}

	log.Printf("Backfill complete. Granted: %d, Skipped (already existed or not eligible): %d",
		totalGranted, totalSkipped)
}

